const roundQty = (value) => Math.round(value * 1000) / 1000;

const poDataList = {{node:search_node_nkWkBdXY.data.data}} || [];
const itemDataList = {{node:search_node_BwcLu7r7.data.data}} || [];
const tableData = {{node:code_node_4r2Fv9G5.data.allData.table_gr}} || [];

const validationErrors = [];

// Build a map of PO line items for quick lookup
const poLineMap = new Map();
for (const poDoc of poDataList) {
  const tablePO = poDoc.table_po || [];
  for (const poItem of tablePO) {
    poLineMap.set(poItem.id, {
      ...poItem,
      po_no: poDoc.po_no,
    });
  }
}

// Build a map of item tolerances from fetched Item data
const itemToleranceMap = new Map();
for (const item of itemDataList) {
  itemToleranceMap.set(item.id, parseFloat(item.over_receive_tolerance || 0));
}

// Aggregate GR quantities per PO line item (skipping split parent rows)
const poLineGrTotals = new Map();

for (const grItem of tableData) {
  // Skip split parent rows - their quantities are managed by split logic
  if (grItem.is_split === "Yes" && grItem.parent_or_child === "Parent") {
    continue;
  }

  const poLineId = grItem.po_line_item_id;
  if (!poLineId) continue;

  const grQty = parseFloat(grItem.received_qty || 0);

  if (poLineGrTotals.has(poLineId)) {
    const existing = poLineGrTotals.get(poLineId);
    existing.totalGrQty = roundQty(existing.totalGrQty + grQty);
  } else {
    poLineGrTotals.set(poLineId, {
      totalGrQty: grQty,
      itemId: grItem.item_id,
      itemName: grItem.item_name || grItem.material_name || "Unknown Item",
    });
  }
}

// Validate aggregated quantities against PO lines
for (const [poLineId, grTotal] of poLineGrTotals) {
  const poItem = poLineMap.get(poLineId);
  if (!poItem) continue;

  const currentReceivedQty = parseFloat(poItem.received_qty || 0);
  const totalAfterReceiving = roundQty(currentReceivedQty + grTotal.totalGrQty);

  // Get tolerance from Item data
  const tolerance = itemToleranceMap.get(grTotal.itemId) || 0;
  const orderedQty = parseFloat(poItem.quantity || 0);
  const maxAllowed = roundQty(orderedQty * ((100 + tolerance) / 100));

  if (totalAfterReceiving > maxAllowed) {
    validationErrors.push(
      `${grTotal.itemName}: Attempting to receive ${grTotal.totalGrQty}, but only ${Math.max(0, roundQty(maxAllowed - currentReceivedQty))} remaining (Ordered: ${orderedQty}, Already received: ${currentReceivedQty}, Max allowed: ${maxAllowed})`
    );
  }
}

const hasErrors = validationErrors.length > 0;
const errorMessage = hasErrors 
  ? `Quantity validation failed:\n${validationErrors.join("\n")}`
  : null;

return {
  hasErrors: hasErrors ? 1 : 0,
  errorMessage: errorMessage,
  validationErrors: validationErrors,
};

